// ---------------------------------------------------------------------------
//  seed-tan-an-neon.js
//
//  Inserts the "Khu Thể Thao Tân An" complex (+ its 5 fields) into your
//  NEON-hosted database, owned by the PhamLeBaDuong account.
//
//  The data below was copied from the local DB. New UUIDs are generated by
//  Neon, and ownership is re-pointed to the owner resolved on Neon (so it does
//  NOT reference the local owner id).
//
//  Safe to re-run: if the complex already exists for that owner, it is reused
//  and only missing fields (matched by name) are added.
//
//  ── HOW TO RUN AGAINST NEON (PowerShell, from the server/ folder) ──────────
//    $env:NEON_DATABASE_URL="postgresql://USER:PASS@HOST/dbname?sslmode=require"
//    node seed-tan-an-neon.js
//
//  (Get the connection string from Neon dashboard → your project → Connect →
//   "Prisma" / "Connection string". Keep ?sslmode=require.)
//
//  Optional overrides:
//    $env:OWNER_USERNAME="PhamLeBaDuong"   # default
//    $env:OWNER_ID="88c94ef4-...."         # use an explicit user id instead
// ---------------------------------------------------------------------------
import "dotenv/config";
import { PrismaClient } from "@prisma/client";

// Prefer an explicit Neon url so we never accidentally hit the local DB.
const DB_URL = process.env.NEON_DATABASE_URL || process.env.DATABASE_URL;
const OWNER_USERNAME = process.env.OWNER_USERNAME || "PhamLeBaDuong";
const OWNER_ID = process.env.OWNER_ID || null;

if (!DB_URL) {
  console.error("❌ Set NEON_DATABASE_URL (or DATABASE_URL) to your Neon connection string.");
  process.exit(1);
}

const prisma = new PrismaClient({ datasources: { db: { url: DB_URL } } });

// Shared operating hours (06:00–23:00). Prisma stores DateTime; only the
// time-of-day is meaningful here, matching how the local rows were created.
const OPEN = new Date("2000-01-01T06:00:00.000Z");
const CLOSE = new Date("2000-01-01T23:00:00.000Z");
const ADDRESS = "71 Đường Tân An, Tân Đông Hiệp, Hồ Chí Minh, Vietnam";

const COMPLEX = {
  name: "Khu Thể Thao Tân An",
  desc: "",
  address: ADDRESS,
  lat: null,
  lng: null,
};

const FIELDS = [
  { name: "Sân 1", type: "5v5", indoor: false, lights: true, pricePerHour: 200000 },
  { name: "Sân 2", type: "5v5", indoor: false, lights: true, pricePerHour: 200000 },
  { name: "Sân 3", type: "5v5", indoor: false, lights: true, pricePerHour: 200000 },
  { name: "Sân 4", type: "5v5", indoor: false, lights: true, pricePerHour: 180000 },
  { name: "Sân 5", type: "5v5", indoor: false, lights: true, pricePerHour: 180000 },
];

async function main() {
  // 1) Resolve the owner account on Neon.
  const owner = OWNER_ID
    ? await prisma.user.findUnique({ where: { id: OWNER_ID } })
    : await prisma.user.findUnique({ where: { username: OWNER_USERNAME } });

  if (!owner) {
    console.error(
      `❌ Owner ${OWNER_ID ? `id "${OWNER_ID}"` : `username "${OWNER_USERNAME}"`} not found in this database.`
    );
    process.exit(1);
  }
  console.log(`👤 Owner: ${owner.name} (@${owner.username}, ${owner.id})`);

  // 2) Reuse an existing complex of the same name for this owner, or create it.
  let complex = await prisma.complex.findFirst({
    where: { name: COMPLEX.name, ownerId: owner.id },
    include: { fields: true },
  });

  if (complex) {
    console.log(`ℹ️  Complex already exists (${complex.id}) — will only add missing fields.`);
  } else {
    complex = await prisma.complex.create({
      data: { ...COMPLEX, ownerId: owner.id },
      include: { fields: true },
    });
    console.log(`✅ Created complex: ${complex.id}`);
  }

  // 3) Add any fields not already present (matched by name).
  const existing = new Set(complex.fields.map((f) => f.name));
  const toCreate = FIELDS.filter((f) => !existing.has(f.name));

  if (toCreate.length === 0) {
    console.log("ℹ️  All 5 fields already present — nothing to add.");
  } else {
    await prisma.field.createMany({
      data: toCreate.map((f) => ({
        ...f,
        complexId: complex.id,
        ownerId: owner.id,
        address: ADDRESS,
        startTime: OPEN,
        endTime: CLOSE,
      })),
    });
    console.log(`✅ Added ${toCreate.length} field(s).`);
  }

  const total = await prisma.field.count({ where: { complexId: complex.id } });
  console.log(`\n📊 Done. "${complex.name}" now has ${total} field(s), owned by @${owner.username}.`);
}

main()
  .catch((e) => {
    console.error("❌ Failed:", e);
    process.exit(1);
  })
  .finally(() => prisma.$disconnect());
